__kernel void benchmark_func(class_T seed, __global class_T* g_data) {
  const uint blockSize = (uint)blockdim;
  const uint lid = get_local_id(0);
  const uint gid = get_global_id(0);
  const uint group = get_group_id(0);

#ifdef BLOCK_STRIDED
  const uint stride = blockSize;
  uint idx = group * blockSize * (uint)ELEMENTS_PER_THREAD + lid;
#else
  const uint stride = get_global_size(0);
  uint idx = gid;
#endif

  const uint big_stride = get_global_size(0) * (uint)ELEMENTS_PER_THREAD;

  class_T tmps[ELEMENTS_PER_THREAD];

  for (uint k = 0; k < (uint)FUSION_DEGREE; k++) {
    for (uint j = 0; j < (uint)ELEMENTS_PER_THREAD; j++) {
      tmps[j] = g_data[idx + j * stride + k * big_stride];
      for (int i = 0; i < (int)COMPUTE_ITERATIONS; i++) {
        tmps[j] = mad_t(tmps[j], tmps[j], seed);
      }
    }

    class_T sum = conv_int(0, (class_T)0);
    for (uint j = 0; j < (uint)ELEMENTS_PER_THREAD; j += 2) {
      sum = mad_t(tmps[j], tmps[j + 1], sum);
    }

    if (equal_t(sum, conv_int(-1, (class_T)0))) {
      g_data[idx + k * big_stride] = sum;
    }
  }
}

