#define MADD(a, b, c) ((a) * (b) + (c))

__kernel void benchmark_func(const class_T seed, __global class_T *g_data) {
  const size_t lid = get_local_id(0);
  const size_t gid = get_global_id(0);
  const size_t group = get_group_id(0);
  const size_t gsize = get_global_size(0);

#ifdef BLOCK_STRIDED
  const size_t stride = (size_t)blockdim;
  size_t idx = group * (size_t)blockdim * (size_t)ELEMENTS_PER_THREAD + lid;
#else
  const size_t stride = gsize;
  size_t idx = gid;
#endif

  const size_t big_stride = gsize * (size_t)ELEMENTS_PER_THREAD;

  class_T tmps[ELEMENTS_PER_THREAD];

  for (int k = 0; k < (int)FUSION_DEGREE; k++) {
    for (int j = 0; j < (int)ELEMENTS_PER_THREAD; j++) {
      tmps[j] = g_data[idx + (size_t)j * stride + (size_t)k * big_stride];
      for (int i = 0; i < (int)COMPUTE_ITERATIONS; i++) {
        tmps[j] = MADD(tmps[j], tmps[j], seed);
      }
    }

    class_T sum = CONV_INT(0);
    for (int j = 0; j < (int)ELEMENTS_PER_THREAD; j += 2) {
      sum = MADD(tmps[j], tmps[j + 1], sum);
    }

    if (IS_EQUAL(sum, CONV_INT(-1))) {
      g_data[idx + (size_t)k * big_stride] = sum;
    }
  }
}
